import React from "react";
import {
  RevampedPageLayout,
  ShadComponents,
} from "@lakefusion/utility-portal";
import {
  ArrowLeft,
  ChevronRight,
} from "lucide-react";
import {
  DocLoader,
  getDocumentMetadata,
} from "../../docs/registry";

const { Button } = ShadComponents;

interface DocViewerProps {
  version?: string;
  path?: string;
}

export const DocViewer: React.FC<DocViewerProps> = ({
  version = "latest",
  path = "user/getting-started",
}) => {
  // Get document metadata for breadcrumb
  const metadata = getDocumentMetadata(path || "");

  // Extract category and title from metadata or path
  const pathParts = path?.split("/") || [];
  const category = metadata?.category || (pathParts[0] === "user" ? "User Guide" : "Developer Guide");
  const title = metadata?.title || pathParts[pathParts.length - 1]?.replace(/-/g, " ").replace(/\b\w/g, (l) => l.toUpperCase()) || "Documentation";

  return (
    <RevampedPageLayout>
      <div className="border border-slate-200 rounded-lg bg-white overflow-hidden flex flex-col h-full">
        {/* Header */}
        <div className="p-4 bg-slate-50/50 border-b border-slate-200 shrink-0">
          <div className="flex items-center gap-3">
            <Button variant="ghost" size="sm" asChild>
              <a href="/selfservice/docs" className="flex items-center gap-1">
                <ArrowLeft className="h-4 w-4" />
                Back
              </a>
            </Button>
            <div className="h-4 w-px bg-slate-300" />
            <nav className="flex items-center text-sm text-slate-500">
              <a href="/selfservice/docs" className="hover:text-primary">
                Documentation
              </a>
              <ChevronRight className="h-4 w-4 mx-1" />
              <span className="text-slate-400">{version}</span>
              <ChevronRight className="h-4 w-4 mx-1" />
              <span className="text-slate-400">{category}</span>
              <ChevronRight className="h-4 w-4 mx-1" />
              <span className="text-slate-900 font-medium">{title}</span>
            </nav>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-auto">
          <div className="max-w-4xl mx-auto px-8 py-8">
            <DocLoader path={path || "user/getting-started"} />
          </div>
        </div>
      </div>
    </RevampedPageLayout>
  );
};

export default DocViewer;
