/**
 * Documentation Registry
 *
 * Maps documentation paths to lazy-loaded MDX components.
 * This allows the DocViewer to dynamically load documentation pages.
 */
import React, { lazy, Suspense } from "react";
import { MDXProvider } from "@mdx-js/react";
import { mdxComponents } from "../components/docs/mdx-components";

// ============================================================================
// Document Metadata
// ============================================================================

export interface DocMetadata {
  path: string;
  title: string;
  description?: string;
  category: string;
  order: number;
}

// Document registry with metadata
export const documentRegistry: Record<
  string,
  {
    component: React.LazyExoticComponent<React.ComponentType<unknown>>;
    metadata: DocMetadata;
  }
> = {
  "user/getting-started": {
    component: lazy(() => import("./user/getting-started.mdx")),
    metadata: {
      path: "user/getting-started",
      title: "Getting Started with LakeFusion",
      description:
        "Learn how to set up LakeFusion and create your first entity",
      category: "Getting Started",
      order: 1,
    },
  },
  // Add more documents here as they are created:
  // "user/entities/index": {
  //   component: lazy(() => import("./user/entities/index.mdx")),
  //   metadata: {...}
  // },
};

// ============================================================================
// Document Loader Component
// ============================================================================

interface DocLoaderProps {
  path: string;
  fallback?: React.ReactNode;
}

export const DocLoader: React.FC<DocLoaderProps> = ({
  path,
  fallback = <DocLoadingSpinner />,
}) => {
  const doc = documentRegistry[path];

  if (!doc) {
    return <DocNotFound path={path} />;
  }

  const MDXContent = doc.component;

  return (
    <MDXProvider components={mdxComponents}>
      <Suspense fallback={fallback}>
        <div className="prose prose-slate max-w-none">
          <MDXContent />
        </div>
      </Suspense>
    </MDXProvider>
  );
};

// ============================================================================
// Helper Components
// ============================================================================

const DocLoadingSpinner: React.FC = () => (
  <div className="flex items-center justify-center py-12">
    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
  </div>
);

const DocNotFound: React.FC<{ path: string }> = ({ path }) => (
  <div className="prose prose-slate max-w-none">
    <div className="bg-amber-50 border border-amber-200 rounded-lg p-6 my-4">
      <h2 className="text-amber-800 mt-0">Documentation Not Found</h2>
      <p className="text-amber-700 mb-0">
        The documentation page at <code>{path}</code> could not be found.
      </p>
      <p className="text-amber-600 text-sm mt-4 mb-0">
        This page may be under construction or the URL might be incorrect.
      </p>
    </div>
  </div>
);

// ============================================================================
// Utility Functions
// ============================================================================

/**
 * Get all available documents
 */
export const getAllDocuments = (): DocMetadata[] => {
  return Object.values(documentRegistry).map((doc) => doc.metadata);
};

/**
 * Get documents by category
 */
export const getDocumentsByCategory = (
  category: string
): DocMetadata[] => {
  return getAllDocuments()
    .filter((doc) => doc.category === category)
    .sort((a, b) => a.order - b.order);
};

/**
 * Get document metadata by path
 */
export const getDocumentMetadata = (
  path: string
): DocMetadata | undefined => {
  return documentRegistry[path]?.metadata;
};

/**
 * Check if a document exists
 */
export const documentExists = (path: string): boolean => {
  return path in documentRegistry;
};

export default DocLoader;
