// ============================================================================
// InteractiveScreenshot Component
// ============================================================================
interface Hotspot {
  x: number;
  y: number;
  tooltip: string;
  pulse?: boolean;
}

interface InteractiveScreenshotProps {
  src: string;
  alt: string;
  hotspots?: Hotspot[];
}

export const InteractiveScreenshot: React.FC<InteractiveScreenshotProps> = ({
  src,
  alt,
  hotspots = [],
}) => {
  const [activeHotspot, setActiveHotspot] = useState<number | null>(null);

  return (
    <figure className="my-6">
      <div className="relative rounded-xl overflow-hidden border border-slate-200 shadow-sm">
        <img
          src={src}
          alt={alt}
          className="w-full h-auto"
          loading="lazy"
        />
        {hotspots.map((hotspot, index) => (
          <div
            key={index}
            className="absolute"
            style={{ left: `${hotspot.x}px`, top: `${hotspot.y}px` }}
          >
            {/* Hotspot marker */}
            <button
              onMouseEnter={() => setActiveHotspot(index)}
              onMouseLeave={() => setActiveHotspot(null)}
              onClick={() => setActiveHotspot(activeHotspot === index ? null : index)}
              className={`
                w-6 h-6 rounded-full bg-primary text-white flex items-center justify-center
                text-xs font-bold shadow-lg cursor-pointer transform -translate-x-1/2 -translate-y-1/2
                hover:scale-110 transition-transform
                ${hotspot.pulse ? "animate-pulse" : ""}
              `}
            >
              {index + 1}
            </button>
            {/* Tooltip */}
            {activeHotspot === index && (
              <div className="absolute left-4 top-0 z-10 w-48 p-2 bg-slate-900 text-white text-xs rounded-lg shadow-xl">
                {hotspot.tooltip}
                <div className="absolute -left-1 top-2 w-2 h-2 bg-slate-900 rotate-45" />
              </div>
            )}
          </div>
        ))}
      </div>
    </figure>
  );
};

