// ============================================================================
// Tabs Component
// ============================================================================
interface TabsProps {
  children: React.ReactNode;
}

interface TabProps {
  label: string;
  children: React.ReactNode;
}

export const Tabs: React.FC<TabsProps> = ({ children }) => {
  const [activeTab, setActiveTab] = useState(0);
  const tabs = React.Children.toArray(children) as React.ReactElement<TabProps>[];

  return (
    <div className="my-6 border border-slate-200 rounded-xl overflow-hidden">
      {/* Tab headers */}
      <div className="flex border-b border-slate-200 bg-slate-50">
        {tabs.map((tab, index) => (
          <button
            key={index}
            onClick={() => setActiveTab(index)}
            className={`
              px-4 py-2 text-sm font-medium transition-colors
              ${activeTab === index
                ? "text-primary border-b-2 border-primary bg-white -mb-px"
                : "text-slate-600 hover:text-slate-900"
              }
            `}
          >
            {tab.props.label}
          </button>
        ))}
      </div>
      {/* Tab content */}
      <div className="p-4">{tabs[activeTab]}</div>
    </div>
  );
};

export const Tab: React.FC<TabProps> = ({ children }) => {
  return <div className="text-sm text-slate-600">{children}</div>;
};

// ============================================================================
// CardGrid Component
// ============================================================================
interface CardGridProps {
  children: React.ReactNode;
}

export const CardGrid: React.FC<CardGridProps> = ({ children }) => {
  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 my-6">
      {children}
    </div>
  );
};

interface CardProps {
  title: string;
  href: string;
  icon?: "database" | "git-merge" | "code";
  children: React.ReactNode;
}

const iconMap = {
  database: Database,
  "git-merge": GitMerge,
  code: Code,
};

export const Card: React.FC<CardProps> = ({ title, href, icon, children }) => {
  const IconComponent = icon ? iconMap[icon] : null;

  return (
    <a
      href={href}
      className="block p-4 border border-slate-200 rounded-xl hover:border-primary hover:shadow-md transition-all group"
    >
      <div className="flex items-start gap-3">
        {IconComponent && (
          <div className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center shrink-0">
            <IconComponent className="h-5 w-5 text-primary" />
          </div>
        )}
        <div>
          <h4 className="font-semibold text-slate-900 group-hover:text-primary transition-colors flex items-center gap-1">
            {title}
            <ExternalLink className="h-3 w-3 opacity-0 group-hover:opacity-100 transition-opacity" />
          </h4>
          <p className="text-sm text-slate-500 mt-1">{children}</p>
        </div>
      </div>
    </a>
  );
};

// ============================================================================
// CodeBlock Component
// ============================================================================
interface CodeBlockProps {
  children: string;
  className?: string;
}

export const CodeBlock: React.FC<CodeBlockProps> = ({ children, className }) => {
  const [copied, setCopied] = useState(false);
  const language = className?.replace("language-", "") || "text";

  const handleCopy = () => {
    navigator.clipboard.writeText(children);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative group my-4">
      <button
        onClick={handleCopy}
        className="absolute right-2 top-2 p-2 rounded-md bg-slate-100 opacity-0 group-hover:opacity-100 transition-opacity z-10"
        title="Copy code"
      >
        {copied ? (
          <Check className="h-4 w-4 text-green-500" />
        ) : (
          <Copy className="h-4 w-4 text-slate-500" />
        )}
      </button>
      <SyntaxHighlighter
        language={language}
        style={oneLight}
        customStyle={{
          borderRadius: "0.75rem",
          padding: "1rem",
          fontSize: "0.875rem",
          border: "1px solid #e2e8f0",
          margin: 0,
        }}
      >
        {String(children).replace(/\n$/, "")}
      </SyntaxHighlighter>
    </div>
  );
};

// ============================================================================
// Pre Component (for MDX code blocks)
// ============================================================================
interface PreProps {
  children: React.ReactNode;
}

export const Pre: React.FC<PreProps> = ({ children }) => {
  // Extract props from the code element
  const codeElement = React.Children.only(children) as React.ReactElement;
  const { children: code, className } = codeElement?.props || {};

  if (typeof code === "string") {
    return <CodeBlock className={className}>{code}</CodeBlock>;
  }

  return <pre className="my-4 p-4 bg-slate-50 rounded-xl border border-slate-200 overflow-auto">{children}</pre>;
};

